class ChatBot:
    def __init__(self, llm, retriever):
        self.history = []
    def chat(self, msg):
        ctx = retriever.search(msg)
        resp = self.llm.invoke(self.history + ctx + msg)
        self.history.append((msg, resp))
        return resp

